const windowDays = 30;
const now = Math.floor(Date.now() / 1000);
const cutoff = now - windowDays * 24 * 60 * 60;

// Use exact run timestamp so each manual run creates a new point.
const pointTs = new Date().toISOString();

const clusters = [
  { cluster: 'silver', mode: 'single', testId: '7719640', slo: 0.995 },
  { cluster: 'emerald', mode: 'single', testId: '7719620', slo: 0.995 },
  { cluster: 'gold', mode: 'single', testId: '7719621', slo: 0.9995 },
  { cluster: 'golddr', mode: 'single', testId: '7719622', slo: 0.9995 },
  { cluster: 'gold-ha', mode: 'pair', primaryId: '7719621', secondaryId: '7719622', slo: 0.9995 },
];

return clusters.map((c) => {
  if (c.mode === 'pair') {
    return {
      json: {
        cluster: c.cluster,
        mode: c.mode,
        primaryId: c.primaryId,
        secondaryId: c.secondaryId,
        slo: c.slo,
        windowDays,
        now,
        cutoff,
        bucketTs: pointTs,
        debug: false,
      }
    };
  }

  return {
    json: {
      cluster: c.cluster,
      mode: c.mode,
      testId: c.testId,
      slo: c.slo,
      windowDays,
      now,
      cutoff,
      bucketTs: pointTs,
      url: 'https://api.statuscake.com/v1/uptime/' + c.testId + '/periods?limit=100',
      totalDownMs: 0,
      debug: false,
    }
  };
});

function toEpoch(s) {
  return Math.floor(new Date(s).getTime() / 1000);
}

function clamp(x, lo, hi) {
  return Math.max(lo, Math.min(hi, x));
}

// Current cluster item from Split Clusters (stable across pagination for that cluster)
const baseState = $items('Split Clusters')[0].json;

// Previous pagination state from this node, if any
const previousState =
  $runIndex > 0
    ? $items('Accumulate + Next1', 0, $runIndex - 1)[0].json
    : null;

// Only continue carrying state when we're still on the same cluster/test
const sameCluster =
  previousState &&
  previousState.cluster === baseState.cluster &&
  String(previousState.testId || '') === String(baseState.testId || '');

const state = sameCluster
  ? { ...previousState, totalDownMs: Number(previousState.totalDownMs || 0) }
  : { ...baseState, totalDownMs: Number(baseState.totalDownMs || 0) };

const resp = $json;
const data = resp.data || [];
let addMs = 0;

for (const p of data) {
  if (p.status !== 'down') continue;
  if (!p.created_at || !p.ended_at) continue;

  const s = toEpoch(p.created_at);
  const e = toEpoch(p.ended_at);
  const os = clamp(s, state.cutoff, state.now);
  const oe = clamp(e, state.cutoff, state.now);
  const overlap = oe - os;

  if (overlap > 0) addMs += overlap * 1000;
}

state.totalDownMs += addMs;

let oldest = state.now;
for (const p of data) {
  if (p.created_at) oldest = Math.min(oldest, toEpoch(p.created_at));
}

const nextUrl = resp.links?.next || null;
const done = (!nextUrl) || (oldest < state.cutoff);

return [{ json: { ...state, url: nextUrl, done } }];

const { primaryId, secondaryId, slo, windowDays, now, cutoff, debug, cluster, bucketTs } = $json;

return [{
  json: {
    cluster,
    bucketTs,
    mode: 'pair',
    primaryId,
    secondaryId,
    slo: Number(slo),
    windowDays: Number(windowDays),
    now: Number(now),
    cutoff: Number(cutoff),
    debug: Boolean(debug),
    phase: 'primary',
    url: 'https://api.statuscake.com/v1/uptime/' + primaryId + '/periods?limit=100',
    primaryIntervals: [],
    secondaryIntervals: [],
    done: false,
  }
}];

function toEpoch(s) {
  return Math.floor(new Date(s).getTime() / 1000);
}

function clamp(x, lo, hi) {
  return Math.max(lo, Math.min(hi, x));
}

const previousState =
  $runIndex > 0
    ? $items('Collect Pair + Next', 0, $runIndex - 1)[0].json
    : $items('Init Pair State')[0].json;

const state = {
  ...previousState,
  primaryIntervals: Array.isArray(previousState.primaryIntervals) ? [...previousState.primaryIntervals] : [],
  secondaryIntervals: Array.isArray(previousState.secondaryIntervals) ? [...previousState.secondaryIntervals] : [],
};

const resp = $json;
const data = resp.data || [];
const target = state.phase === 'primary' ? state.primaryIntervals : state.secondaryIntervals;

for (const p of data) {
  if (p.status !== 'down') continue;
  if (!p.created_at || !p.ended_at) continue;

  const s = toEpoch(p.created_at);
  const e = toEpoch(p.ended_at);
  const os = clamp(s, state.cutoff, state.now);
  const oe = clamp(e, state.cutoff, state.now);

  if (oe > os) target.push({ start: os, end: oe });
}

let oldest = state.now;
for (const p of data) {
  if (p.created_at) oldest = Math.min(oldest, toEpoch(p.created_at));
}

const nextUrl = resp.links?.next || null;
const phaseDone = (!nextUrl) || (oldest < state.cutoff);

if (!phaseDone) {
  state.url = nextUrl;
  state.done = false;
} else if (state.phase === 'primary') {
  state.phase = 'secondary';
  state.url = 'https://api.statuscake.com/v1/uptime/' + state.secondaryId + '/periods?limit=100';
  state.done = false;
} else {
  state.phase = 'complete';
  state.url = null;
  state.done = true;
}

return [{ json: state }];

function normalize(intervals) {
  const sorted = [...intervals]
    .filter(i => Number(i.end) > Number(i.start))
    .map(i => ({ start: Number(i.start), end: Number(i.end) }))
    .sort((a, b) => a.start - b.start || a.end - b.end);

  const merged = [];
  for (const cur of sorted) {
    if (!merged.length || cur.start > merged[merged.length - 1].end) merged.push({ ...cur });
    else merged[merged.length - 1].end = Math.max(merged[merged.length - 1].end, cur.end);
  }
  return merged;
}

const primary = normalize($json.primaryIntervals || []);
const secondary = normalize($json.secondaryIntervals || []);

let i = 0;
let j = 0;
let overlapSeconds = 0;

while (i < primary.length && j < secondary.length) {
  const s = Math.max(primary[i].start, secondary[j].start);
  const e = Math.min(primary[i].end, secondary[j].end);
  if (e > s) overlapSeconds += e - s;
  if (primary[i].end <= secondary[j].end) i += 1;
  else j += 1;
}

return [{
  json: {
    cluster: $json.cluster,
    bucketTs: $json.bucketTs,
    slo: Number($json.slo),
    windowDays: Number($json.windowDays),
    totalDownMs: overlapSeconds * 1000,
  }
}];

const { slo, windowDays, totalDownMs } = $json;
const windowSeconds = windowDays * 24 * 60 * 60;
const allowedSeconds = Math.floor(windowSeconds * (1 - slo));
const usedSeconds = Math.floor(totalDownMs / 1000);
const remainingSeconds = Math.max(0, allowedSeconds - usedSeconds);
const remainingMinutes = +(remainingSeconds / 60).toFixed(2);

return [{
  json: {
    cluster: $json.cluster,
    bucketTs: $json.bucketTs,
    windowDays,
    slo,
    allowedSeconds,
    usedSeconds,
    remainingSeconds,
    remainingMinutes,
    downtimeUsedMs: totalDownMs
  }
}];

const cluster = String($json.cluster || '').toLowerCase();
const tsRaw = $json.bucketTs ? String($json.bucketTs) : new Date().toISOString();
const parsed = new Date(tsRaw);
const bucketTs = Number.isFinite(parsed.getTime()) ? parsed.toISOString() : new Date().toISOString();
const valueMinutes = Number($json.remainingMinutes);

const safeCluster = cluster.replace(/'/g, "''");
const safeTs = bucketTs.replace(/'/g, "''");
const safeValue = Number.isFinite(valueMinutes) ? valueMinutes : 0;

const upsertSql = [
  'INSERT INTO public.error_budget_timeseries (cluster, bucket_ts, value_minutes)',
  "VALUES ('" + safeCluster + "', '" + safeTs + "'::timestamptz, " + safeValue + ')',
  'ON CONFLICT (cluster, bucket_ts)',
  'DO UPDATE SET value_minutes = EXCLUDED.value_minutes, updated_at = now()',
  'RETURNING cluster, bucket_ts, value_minutes, updated_at;'
].join('\n');

return [{ json: { ...$json, bucketTs, upsertSql } }];

const windowDays = 30;
const lookbackDays = 60;
const now = Math.floor(Date.now() / 1000);
const cutoff = now - lookbackDays * 24 * 60 * 60;

const checks = [
  { cluster: 'clab', testId: '7719616' },
  { cluster: 'klab', testId: '7719618' },
  { cluster: 'emerald', testId: '7719620' },
  { cluster: 'gold', testId: '7719621' },
  { cluster: 'golddr', testId: '7719622' },
  { cluster: 'silver', testId: '7719640' },
];

return checks.map((c) => ({
  json: {
    ...c,
    windowDays,
    lookbackDays,
    now,
    cutoff,
    url: 'https://api.statuscake.com/v1/uptime/' + c.testId + '/periods?limit=100',
    downtimeRows: [],
    done: false,
  }
}));

function toEpoch(s) {
  const t = new Date(s).getTime();
  return Number.isFinite(t) ? Math.floor(t / 1000) : null;
}

function clamp(x, lo, hi) {
  return Math.max(lo, Math.min(hi, x));
}

const baseState = $items('Split Checks')[0].json;
const previousState = $runIndex > 0 ? $items('Collect Rows + Next', 0, $runIndex - 1)[0].json : null;
const sameCheck = previousState && previousState.cluster === baseState.cluster && String(previousState.testId) === String(baseState.testId);
const state = sameCheck
  ? { ...previousState, downtimeRows: Array.isArray(previousState.downtimeRows) ? [...previousState.downtimeRows] : [] }
  : { ...baseState, downtimeRows: [] };

const resp = $json;
const data = Array.isArray(resp.data) ? resp.data : [];

for (const p of data) {
  if (String(p.status || '').toLowerCase() !== 'down') continue;
  if (!p.created_at) continue;

  const start = toEpoch(p.created_at);
  const rawEnd = p.ended_at ? toEpoch(p.ended_at) : state.now;
  if (start === null || rawEnd === null) continue;

  const os = clamp(start, state.cutoff, state.now);
  const oe = clamp(rawEnd, state.cutoff, state.now);
  if (oe <= os) continue;

  const periodId = String(p.id || p.period_id || p.uuid || [state.testId, p.created_at].join(':'));
  state.downtimeRows.push({
    cluster: state.cluster,
    testId: String(state.testId),
    periodId,
    startedAt: new Date(os * 1000).toISOString(),
    endedAt: new Date(oe * 1000).toISOString(),
    durationSeconds: oe - os,
    sourceStatus: String(p.status || 'down'),
    raw: p,
  });
}

let oldest = state.now;
for (const p of data) {
  if (p.created_at) {
    const t = toEpoch(p.created_at);
    if (t !== null) oldest = Math.min(oldest, t);
  }
}

const nextUrl = resp.links?.next || null;
state.done = (!nextUrl) || (oldest < state.cutoff);
state.url = state.done ? null : nextUrl;

return [{ json: state }];

function sqlString(value) {
  if (value === null || value === undefined) return 'NULL';
  return "'" + String(value).replace(/'/g, "''") + "'";
}

function sqlJson(value) {
  return sqlString(JSON.stringify(value || {})) + '::jsonb';
}

const rows = Array.isArray($json.downtimeRows) ? $json.downtimeRows : [];
const cleanupSql = "DELETE FROM public.statuscake_downtime_periods WHERE ended_at < now() - interval '90 days' RETURNING 1";

if (!rows.length) {
  const upsertSql = [
    'WITH cleanup AS (',
    '  ' + cleanupSql,
    ')',
    'SELECT 0 AS upserted_rows, (SELECT count(*) FROM cleanup) AS deleted_old_rows;'
  ].join('\n');

  return [{ json: { ...$json, upsertSql } }];
}

const values = rows.map((r) => [
  sqlString(r.cluster),
  sqlString(r.testId),
  sqlString(r.periodId),
  sqlString(r.startedAt) + '::timestamptz',
  sqlString(r.endedAt) + '::timestamptz',
  Number.isFinite(Number(r.durationSeconds)) ? Math.max(0, Math.floor(Number(r.durationSeconds))) : 0,
  sqlString(r.sourceStatus || 'down'),
  sqlJson(r.raw),
].join(', '));

const upsertSql = [
  'WITH upserted AS (',
  '  INSERT INTO public.statuscake_downtime_periods',
  '    (cluster, test_id, period_id, started_at, ended_at, duration_seconds, source_status, raw)',
  '  VALUES',
  values.map((v) => '    (' + v + ')').join(',\n'),
  '  ON CONFLICT (test_id, period_id) DO UPDATE SET',
  '    cluster = EXCLUDED.cluster,',
  '    started_at = EXCLUDED.started_at,',
  '    ended_at = EXCLUDED.ended_at,',
  '    duration_seconds = EXCLUDED.duration_seconds,',
  '    source_status = EXCLUDED.source_status,',
  '    raw = EXCLUDED.raw,',
  '    imported_at = now(),',
  '    updated_at = now()',
  '  RETURNING 1',
  '), cleanup AS (',
  '  ' + cleanupSql,
  ')',
  'SELECT',
  '  (SELECT count(*) FROM upserted) AS upserted_rows,',
  '  (SELECT count(*) FROM cleanup) AS deleted_old_rows;'
].join('\n');

return [{ json: { ...$json, upsertSql } }];
